import { useParams, useNavigate } from 'react-router-dom';
import { products } from '../Data/product';
import { useCart } from '../Context/CartContext';
import './ProductDetailPage.css';

const ProductDetailPage = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { addToCart } = useCart();

    const product = products.find(p => p.id === parseInt(id));

    if (!product) {
        return (
            <div className="product-not-found">
                <h2>Producto no encontrado</h2>
                <button onClick={() => navigate('/')} className="btn-secondary back-btn">
                    Volver al catálogo
                </button>
            </div>
        );
    }

    const bannerItems = products.filter(p => {
        const hasSameName = p.name === product.name;
        const isBanner = Array.isArray(p.type) 
            ? p.type.includes('banner') 
            : p.type === 'banner';
        
        return hasSameName && isBanner;
    });

    let carouselImages = [product.image];

    bannerItems.forEach(item => {
        carouselImages.push(item.image);
    });

    // (Opcional) Eliminar duplicados si la imagen principal también está marcada como banner
    carouselImages = [...new Set(carouselImages)];


    return (
        <div className="product-detail-container">
            <div>
                <img
                    src={product.image}
                    alt={product.name}
                    className="product-detail-image"
                />
            </div>

            <div>
                <div className="product-detail-category">
                    {product.category}
                </div>
                <h1 className="product-detail-title">{product.name}</h1>
                <div className="product-detail-price">
                    ${product.price.toFixed(2)}
                </div>

                <p className="product-detail-description">
                    {product.description}
                </p>

                <div className="product-detail-actions">
                    <button
                        onClick={() => addToCart(product)}
                        className="btn-primary add-to-cart-btn"
                    >
                        Agregar al Carrito
                    </button>
                    {/* TODO: Implementar lista de deseos */}
                    <button className="btn-secondary wishlist-btn">
                        ♥
                    </button>
                </div>

                <div className="product-specs">
                    <h3 className="specs-title">Detalles</h3>
                    <ul className="specs-list">
                        <li className="specs-item">• 100% Algodón</li>
                        <li className="specs-item">• Estampado de alta durabilidad</li>
                        <li className="specs-item">• Corte Unisex</li>
                        <li className="specs-item">• Unitalla</li>
                        <li className="specs-item">• Color Unico</li>
                        <li>• Hecho en México</li>
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default ProductDetailPage;
